1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("quote — single item base premiums (R1)", () => {
6	    it("amulet alone → base premium 60 G (before fee, no other modifiers)", () => {
7	      const result = quote({ yearsWithMHPCO: 0 }, [{ type: "amulet" }], { followUp: false });
8	      expect(result.basePremium).toBe(60);
9	    });
10	    it("sword alone → base premium 100 G", () => {
11	      const result = quote({ yearsWithMHPCO: 0 }, [{ type: "sword" }], { followUp: false });
12	      expect(result.basePremium).toBe(100);
13	    });
14	    it.todo("staff alone → base premium 80 G");
15	    it.todo("potion alone → base premium 40 G");
16	    it.todo("a single rune → base premium 25 G");
17	    it.todo("empty item list → premium 5 G (processing fee only)");
18	  });
19	
20	  describe("quote — component building blocks (R2, R3)", () => {
21	    it.todo("2 runes → base premium 50 G (below block size, 2×25)");
22	    it.todo("3 runes → base premium 60 G (block of exactly 3 applies)");
23	    it.todo("4 runes → base premium 100 G (no block — block requires exactly 3, 4×25)");
24	    it.todo("7 runes → base premium 175 G (no block — 7×25)");
25	    it.todo("2 runes + 1 moonstone → base premium 75 G (no block: different types, 3×25)");
26	    it.todo("3 runes + 3 moonstones → base premium 120 G (two separate blocks, 60 + 60)");
27	  });
28	
29	  describe("quote — premium modifiers and scope (R4, R5)", () => {
30	    it.todo("cursed sword adds 50% to the item base premium → 150 G base+surcharge (before policy modifiers and fee)");
31	    it.todo("sword with enchantment exactly 5 → high-enchantment 30% surcharge applies");
32	    it.todo("sword with enchantment 4 → no high-enchantment surcharge");
33	    it.todo("customer with exactly 2 years → 20% loyalty discount applies");
34	    it.todo("policy with cursed sword (100) + plain amulet (60) → 210 G before policy-wide modifiers and fee (cursed surcharge 50 = 50% of sword base only)");
35	  });
36	
37	  describe("quote — integration examples (R4, R5, R8)", () => {
38	    it.todo("newcomer (0 yrs), cursed sword (steel, ench 3) → premium 165 G (100 base + 50 curse + 10 first-insurance + 5 fee)");
39	    it.todo("long-standing customer (3 yrs), second quote, cursed sword (steel, ench 7) → premium 160 G (100 + 50 curse + 30 high-ench − 20 loyalty + 10 first-ins − 15 follow-up + 5 fee)");
40	    it.todo("premium that computes to 197.5 G → rounded up to 198 G (MHPCO favor)");
41	  });
42	
43	  describe("claim — standard reimbursement and clauses (R7)", () => {
44	    it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (500 − 100 deductible)");
45	    it.todo("rune (insurance value 250 G), damage 200 G → payout 100 G (200 − 100, no special clause)");
46	    it.todo("dragon-material sword, enchantment exactly 8, damage 1000 G → payout 400 G (50% clause then deductible: 500 − 100)");
47	    it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (dragon full reimbursement then deductible: 800 − 100)");
48	    it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (high-ench 50% then deductible: 500 − 100)");
49	    it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins over dragon, then deductible)");
50	    it.todo("dragon attack: sword damaged 500 G + amulet damaged 300 G → payout 600 G (100 G deductible per damaged item)");
51	    it.todo("payout that computes to 350.5 G → rounded down to 350 G (MHPCO favor)");
52	  });
53	
54	  describe("claim — caps and exhaustion (R7)", () => {
55	    it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G (2× sum of insurance values)");
56	    it.todo("cursed sword (value 1000, premium 165) → cap 2000 G (based on unmodified insurance value)");
57	    it.todo("sword + 3 runes (block) → insurance sum 1750 G (1000 + 3×250; block discount affects premium only)");
58	    it.todo("sword (cap 2000), two successive 1500 G claims → first payout 1400 G (remaining cap 600), second payout 600 G (remaining cap 0)");
59	    it.todo("two swords → insurance sum 2000 G, cap 4000 G");
60	    it.todo("two swords both damaged (two sword damage entries) → each treated as separate damage with its own 100 G deductible");
61	  });
62	});
